import{_ as e,c as t,o as l,U as o}from"./chunks/framework.V7QYn7G9.js";const h=JSON.parse('{"title":"Lesli Ecosystem","description":"","frontmatter":{},"headers":[],"relativePath":"about/ecosystem.md","filePath":"about/ecosystem.md","lastUpdated":1707090984000}'),i={name:"about/ecosystem.md"},a=o('<h1 id="lesli-ecosystem" tabindex="-1">Lesli Ecosystem <a class="header-anchor" href="#lesli-ecosystem" aria-label="Permalink to &quot;Lesli Ecosystem&quot;">​</a></h1><h2 id="collections-and-modules" tabindex="-1">Collections and Modules <a class="header-anchor" href="#collections-and-modules" aria-label="Permalink to &quot;Collections and Modules&quot;">​</a></h2><p>Lesli core is meant to work with modules (Standard RoR engines) to extend the Lesli features and create custom software as required.</p><p>There are several engines created and ready for production developed by the Lesli team, must of them are open source.</p><h3 id="collections" tabindex="-1">Collections <a class="header-anchor" href="#collections" aria-label="Permalink to &quot;Collections&quot;">​</a></h3><p>A collection is a group of modules that belongs to a category or a business industry.</p><ol><li>Administration</li><li>Sales &amp; Marketing</li><li>Productivity &amp; Teamwork</li><li>Finance</li><li>Analytics</li><li>Intelligence</li><li>IT &amp; Help Desk</li><li>Security &amp; Privacy</li><li>Integrations</li></ol><h3 id="module-ecosystem" tabindex="-1">Module ecosystem <a class="header-anchor" href="#module-ecosystem" aria-label="Permalink to &quot;Module ecosystem&quot;">​</a></h3><p>Currently we have planned the development of 45 modules, 24 modules are already developed and ready for production.</p><p><strong>Lesli core:</strong></p><ol><li>User administration</li><li>Role &amp; privilege management</li><li>Document templates</li><li>Mailing system</li><li>Workflows</li></ol><p><strong>01 Administration:</strong></p><ol><li>Team: Human Resources Management</li></ol><p><strong>02 Sales &amp; Marketing:</strong></p><ol start="4"><li>House: Advanced real estate management</li><li>Mailer: Email automation system</li><li>Proposal*: Proposal and quotation management</li></ol><p><strong>03 Productivity &amp; Teamwork:</strong></p><ol><li>Driver: Unified calendar app</li><li>Work: Dynamic Project Management Assistant</li><li>Focus: Task Management</li><li>Text: Notes &amp; Notebooks</li><li>Bell: Notification system</li><li>Talk*: Business communication platform (chat, voice calls, video calls through WebRTC)</li></ol><p><strong>04 Finance:</strong></p><ol><li>Books*: Accounting System</li><li>Things: Inventory management</li><li>Realty*: Real Estate Administration &amp; Investment</li></ol><p><strong>05 Analytics:</strong></p><p><strong>06 Intelligence:</strong></p><ol start="6"><li>Workflows: Process automation</li></ol><p><strong>07 IT &amp; Help Desk:</strong></p><ol start="2"><li>Help: Support Ticket System</li><li>Portal: Client Portal (customer dashboard)</li><li>Shared: Free &amp; Open resources</li></ol><p><strong>08 Security &amp; Privacy:</strong></p><ol><li>Audit*: System log analytics</li><li>Administration: Core system settings</li><li>Vault: Security management</li><li>Authority: Multi account administration</li></ol><p><strong>09 Integrations:</strong></p><ol><li>Babel: Translation management</li><li>Dispatcher: HTTP REST Web API</li><li>Federation*: Cloud collaboration engine</li><li>One: Cloud Infrastructure Management</li><li>MobileApp: Multi platform mobile application</li></ol><p><br><br></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>You can create your own modules, we&#39;ll cover that part later in this documentation.</p></div>',30),s=[a];function n(r,c,m,d,p,u){return l(),t("div",null,s)}const y=e(i,[["render",n]]);export{h as __pageData,y as default};
